import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PromptCategory {
  SOFTWARE = 'SOFTWARE',
  INTERFACE = 'INTERFACE',
  INTERACTION = 'INTERACTION',
  EMOTIONAL_IP = 'EMOTIONAL_IP',
}

export interface PromptTemplate {
  id: PromptCategory;
  label: string;
  icon: string; // Lucide icon name
  description: string;
  placeholder: string;
  systemInstruction: string;
}

export interface OptimizationResult {
  original: string;
  optimized: string;
  category: PromptCategory;
  timestamp: number;
}

import { GoogleGenAI } from "@google/genai";
import { PromptCategory } from '../types';
import { CATEGORIES } from '../constants';

const apiKey = process.env.API_KEY;

// Initialize the client.
// Note: In a real production app, we might handle missing keys more gracefully in the UI.
const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key-for-types' });

export const generateOptimizedPrompt = async (
  category: PromptCategory,
  userInput: string
): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  const template = CATEGORIES[category];

  // We use the flash model for speed and efficiency in text transformation.
  const modelId = "gemini-3-flash-preview";

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: userInput,
      config: {
        systemInstruction: template.systemInstruction,
        temperature: 0.7, // Balance between creativity and structure
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No content generated.");
    }
    return text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { PromptTemplate } from '../types';
import * as Icons from 'lucide-react';

interface CategoryCardProps {
  template: PromptTemplate;
  isSelected: boolean;
  onClick: () => void;
}

export const CategoryCard: React.FC<CategoryCardProps> = ({ template, isSelected, onClick }) => {
