          ? 'border-primary-600 bg-primary-50 text-primary-900 shadow-sm' 
          : 'border-slate-200 bg-white text-slate-600'
        }
      `}
    >
      <div className={`
        p-2 rounded-lg mb-3
        ${isSelected ? 'bg-primary-200 text-primary-700' : 'bg-slate-100 text-slate-500'}
