import React from 'react';
import { Send, Loader2 } from 'lucide-react';

interface InputSectionProps {
  value: string;
  onChange: (val: string) => void;
  onSubmit: () => void;
  isLoading: boolean;
  placeholder: string;
}

export const InputSection: React.FC<InputSectionProps> = ({ 
  value, 
  onChange, 
  onSubmit, 
  isLoading,
  placeholder 
}) => {

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      onSubmit();
    }
  };

  return (
    <div className="flex flex-col gap-4 w-full">
      <div className="relative">
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          disabled={isLoading}
          className="w-full h-48 p-4 rounded-xl border border-slate-300 bg-white shadow-sm focus:ring-2 focus:ring-primary-500 focus:border-transparent outline-none resize-none text-slate-800 placeholder-slate-400 font-sans text-base transition-all disabled:bg-slate-50 disabled:text-slate-400"
        />
        <div className="absolute bottom-4 right-4 text-xs text-slate-400 pointer-events-none">
          CMD + Enter to submit
        </div>
      </div>

      <div className="flex justify-end">
        <button
          onClick={onSubmit}
          disabled={isLoading || !value.trim()}
          className={`
            flex items-center gap-2 px-6 py-3 rounded-lg font-medium text-white transition-all
            ${isLoading || !value.trim() 
              ? 'bg-slate-400 cursor-not-allowed opacity-70' 
              : 'bg-primary-600 hover:bg-primary-700 shadow-md hover:shadow-lg active:scale-95'
            }
          `}
        >
          {isLoading ? (
            <>
              <Loader2 className="animate-spin" size={20} />
              <span>Optimizing...</span>
            </>
          ) : (
            <>
              <Send size={20} />
              <span>Generate Prompt</span>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check, RefreshCw } from 'lucide-react';

interface OutputSectionProps {
  content: string;
  categoryLabel: string;
  onReset?: () => void;
}

export const OutputSection: React.FC<OutputSectionProps> = ({ content, categoryLabel, onReset }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  return (
    <div className="flex flex-col gap-4 w-full h-full animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
           <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-bold uppercase rounded tracking-wider">
            Optimized
           </span>
           <span className="text-slate-500 text-sm font-medium">for {categoryLabel}</span>
        </div>

        <div className="flex items-center gap-2">
          {onReset && (
             <button 
              onClick={onReset}
              className="p-2 text-slate-500 hover:text-primary-600 hover:bg-slate-100 rounded-lg transition-colors"
              title="Reset"
             >
               <RefreshCw size={18} />
             </button>
          )}
          <button
            onClick={handleCopy}
            className={`
              flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all
              ${copied 
                ? 'bg-green-600 text-white' 
                : 'bg-white border border-slate-300 text-slate-700 hover:bg-slate-50 hover:text-primary-700'
              }
            `}
          >
            {copied ? <Check size={16} /> : <Copy size={16} />}
            {copied ? 'Copied!' : 'Copy'}
          </button>
        </div>
      </div>

      <div className="relative flex-grow">
        <div className="w-full h-full min-h-[400px] p-6 rounded-xl border border-slate-200 bg-white shadow-sm overflow-auto">
          <pre className="whitespace-pre-wrap font-mono text-sm text-slate-800 leading-relaxed">
            {content}
          </pre>
        </div>
        {/* Decorative flair */}
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary-400 via-purple-500 to-primary-600 rounded-t-xl opacity-80" />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CATEGORIES } from './constants';
import { PromptCategory } from './types';
import { CategoryCard } from './components/CategoryCard';
import { InputSection } from './components/InputSection';
import { OutputSection } from './components/OutputSection';
import { generateOptimizedPrompt } from './services/geminiService';
import { Sparkles, Terminal, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<PromptCategory>(PromptCategory.SOFTWARE);
  const [inputText, setInputText] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!inputText.trim()) return;

    setIsLoading(true);
    setError(null);
    setResult(null);

    try {
      const optimizedText = await generateOptimizedPrompt(selectedCategory, inputText);
      setResult(optimizedText);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred while generating the prompt.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = () => {
    setResult(null);
    setInputText('');
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
