          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-br from-primary-500 to-purple-600 p-2 rounded-lg text-white shadow-lg shadow-primary-500/20">
              <Terminal size={24} strokeWidth={2.5} />
            </div>
            <div>
              <h1 className="font-bold text-xl tracking-tight text-slate-900">PM Prompt Forge</h1>
              <p className="text-xs text-slate-500 font-medium tracking-wide uppercase">Product Manager AI Toolkit</p>
            </div>
          </div>
          <div className="hidden md:flex items-center gap-4 text-sm text-slate-500">
             <span>v1.0.0</span>
             <a href="#" className="hover:text-primary-600 transition-colors">Documentation</a>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Intro Section (Only show if no result) */}
        {!result && (
          <div className="mb-8 text-center max-w-2xl mx-auto">
            <h2 className="text-3xl font-bold text-slate-900 mb-3">Optimize your Product logic.</h2>
            <p className="text-slate-600 text-lg">
              Select a domain and transform rough ideas into professional, structural prompts for LLMs.
            </p>
