                </label>
                <div className={`grid gap-4 ${result ? 'grid-cols-1' : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-4'}`}>
                  {(Object.keys(CATEGORIES) as PromptCategory[]).map((catKey) => (
                    <CategoryCard
                      key={catKey}
                      template={CATEGORIES[catKey]}
                      isSelected={selectedCategory === catKey}
                      onClick={() => {
                        setSelectedCategory(catKey);
                        // If we have a result, maybe clear it or keep it? 
                        // Let's keep it but user has to click generate again to update.
                      }}
                    />
                  ))}
                </div>
             </div>

             {/* Input Area */}
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <label className="block text-sm font-semibold text-slate-700 mb-3 flex items-center justify-between">
                  <span className="uppercase tracking-wider">Raw Input</span>
                  <span className="text-xs font-normal text-slate-400">Be detailed for best results</span>
                </label>
                <InputSection
