import React from 'react';
import { Send, Loader2, Settings2, Languages, Volume2 } from 'lucide-react';
import { ToneType, LangType } from '../types';
import { TONE_OPTIONS, LANG_OPTIONS } from '../constants';

interface InputSectionProps {
  value: string;
  onChange: (val: string) => void;
  onSubmit: () => void;
  isLoading: boolean;
  placeholder: string;
  tone: ToneType;
  setTone: (t: ToneType) => void;
  lang: LangType;
  setLang: (l: LangType) => void;
}

export const InputSection: React.FC<InputSectionProps> = ({ 
  value, 
  onChange, 
  onSubmit, 
  isLoading,
  placeholder,
  tone,
  setTone,
  lang,
  setLang
}) => {

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      onSubmit();
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full">
      {/* Options Bar */}
      <div className="flex flex-col sm:flex-row gap-4">

        {/* Tone Selector */}
        <div className="flex-1">
          <label className="text-xs font-extrabold text-game-textLight uppercase tracking-wider mb-2 block ml-1">
            语气风格
          </label>
          <div className="relative">
             <div className="absolute left-3 top-1/2 -translate-y-1/2 text-game-blue">
                <Volume2 size={20} />
             </div>
             <select 
               value={tone}
               onChange={(e) => setTone(e.target.value as ToneType)}
               className="w-full pl-10 pr-4 py-3 rounded-2xl border-2 border-game-gray border-b-4 border-b-game-grayDark bg-white text-game-text font-bold focus:outline-none focus:border-game-blue focus:border-b-game-blueDark appearance-none cursor-pointer hover:bg-gray-50 transition-colors"
             >
               {Object.entries(TONE_OPTIONS).map(([key, label]) => (
                 <option key={key} value={key}>{label}</option>
               ))}
             </select>
          </div>
        </div>

        {/* Language Selector */}
        <div className="flex-1">
           <label className="text-xs font-extrabold text-game-textLight uppercase tracking-wider mb-2 block ml-1">
             输出语言
           </label>
           <div className="flex gap-2">
             {Object.entries(LANG_OPTIONS).map(([key, label]) => {
                const isActive = lang === key;
                return (
                 <button
                   key={key}
                   onClick={() => setLang(key as LangType)}
                   className={`
                     flex-1 py-3 rounded-2xl font-bold border-2 border-b-4 transition-all btn-3d text-sm
                     ${isActive 
                       ? 'bg-game-blue border-game-blue border-b-game-blueDark text-white' 
                       : 'bg-white border-game-gray border-b-game-grayDark text-game-textLight hover:bg-gray-50'
                     }
                   `}
                 >
                   {key === 'ZH' ? '中文' : 'EN'}
                 </button>
                )
             })}
           </div>
        </div>
      </div>

      <div className="relative">
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          disabled={isLoading}
          className="w-full h-48 p-5 rounded-3xl border-2 border-game-gray border-b-4 border-b-game-grayDark bg-white focus:outline-none focus:border-game-green focus:border-b-game-greenDark resize-none text-game-text placeholder-game-textLight font-bold text-lg transition-all"
        />
        <div className="absolute bottom-5 right-5 text-xs font-bold text-game-textLight pointer-events-none opacity-50 hidden sm:block">
          CMD + ENTER
        </div>
      </div>

      <button
        onClick={onSubmit}
        disabled={isLoading || !value.trim()}
        className={`
          w-full sm:w-auto self-end flex items-center justify-center gap-3 px-8 py-4 rounded-2xl font-extrabold text-lg text-white transition-all border-b-4 btn-3d
          ${isLoading || !value.trim() 
            ? 'bg-game-gray text-game-textLight border-game-grayDark cursor-not-allowed opacity-70' 
            : 'bg-game-green border-game-greenDark hover:brightness-110 active:border-b-0 active:mt-1'
          }
        `}
      >
        {isLoading ? (
          <>
            <Loader2 className="animate-spin" size={24} strokeWidth={3} />
            <span>AI 思考中...</span>
          </>
        ) : (
          <>
            <span>生成提示词</span>
            <Send size={24} strokeWidth={3} />
          </>
        )}
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check, RefreshCw, Star } from 'lucide-react';

interface OutputSectionProps {
  content: string;
  categoryLabel: string;
  onReset?: () => void;
}

export const OutputSection: React.FC<OutputSectionProps> = ({ content, categoryLabel, onReset }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  return (
    <div className="flex flex-col w-full h-full animate-in zoom-in-95 duration-300">

      {/* Success Banner */}
      <div className="mb-4 flex items-center justify-between">
         <div>
            <h2 className="text-2xl font-extrabold text-game-green flex items-center gap-2">
               <Star className="fill-current" />
               <span>优化完成!</span>
            </h2>
            <p className="text-game-textLight font-bold text-sm ml-1">
               针对 <span className="text-game-blue">{categoryLabel}</span> 场景
            </p>
         </div>

         <div className="flex gap-2">
            {onReset && (
               <button 
                onClick={onReset}
                className="p-3 rounded-xl border-2 border-game-gray border-b-4 border-b-game-grayDark text-game-textLight hover:bg-gray-50 hover:text-game-red transition-all btn-3d"
                title="重置"
               >
                 <RefreshCw size={20} strokeWidth={3} />
               </button>
            )}
            <button
              onClick={handleCopy}
              className={`
                flex items-center gap-2 px-5 py-3 rounded-xl font-extrabold border-b-4 transition-all btn-3d
                ${copied 
                  ? 'bg-white border-2 border-game-green text-game-green border-b-game-green' 
                  : 'bg-game-blue border-game-blueDark text-white hover:brightness-110'
                }
              `}
            >
              {copied ? <Check size={20} strokeWidth={4} /> : <Copy size={20} strokeWidth={3} />}
              {copied ? '已复制' : '复制结果'}
            </button>
         </div>
      </div>

      <div className="relative flex-grow">
        <div className="w-full h-full min-h-[400px] p-6 rounded-3xl border-2 border-game-gray border-b-4 border-b-game-grayDark bg-white shadow-sm overflow-auto">
          <pre className="whitespace-pre-wrap font-mono text-sm text-game-text leading-relaxed">
            {content}
          </pre>
        </div>
      </div>
    </div>
  );
};

