import React from 'react';
import { Send, Loader2, Sparkles, Languages, Mic } from 'lucide-react';
import { ToneType, LangType } from '../types';
import { TONE_OPTIONS, LANG_OPTIONS } from '../constants';

interface InputSectionProps {
  value: string;
  onChange: (val: string) => void;
  onSubmit: () => void;
  isLoading: boolean;
  placeholder: string;
  tone: ToneType;
  setTone: (t: ToneType) => void;
  lang: LangType;
  setLang: (l: LangType) => void;
}

export const InputSection: React.FC<InputSectionProps> = ({ 
  value, 
  onChange, 
  onSubmit, 
  isLoading,
  placeholder,
  tone,
  setTone,
  lang,
  setLang
}) => {

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      onSubmit();
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full h-full justify-between">
      {/* Input Area */}
      <div className="relative flex-grow group">
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          disabled={isLoading}
          className="w-full h-full min-h-[200px] bg-transparent border-0 focus:ring-0 p-0 text-lg text-slate-700 placeholder-slate-400 font-medium resize-none leading-relaxed"
          style={{ fontFamily: '"Plus Jakarta Sans", sans-serif' }}
        />
        {/* Floating gradient line at bottom that activates on focus is handled by container border */}
      </div>

      {/* Controls & Actions */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 pt-6 border-t border-slate-200/60">

        <div className="flex items-center gap-3 w-full sm:w-auto">
           {/* Tone Pill */}
           <div className="relative group">
             <select 
               value={tone}
               onChange={(e) => setTone(e.target.value as ToneType)}
               className="appearance-none bg-slate-100 hover:bg-slate-200 text-slate-600 font-semibold text-xs py-2 pl-4 pr-8 rounded-full cursor-pointer transition-colors focus:outline-none focus:ring-2 focus:ring-neo-primary/20"
             >
               {Object.entries(TONE_OPTIONS).map(([key, label]) => (
                 <option key={key} value={key}>{label}</option>
               ))}
             </select>
             <Sparkles size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
           </div>

           {/* Lang Pill */}
           <div className="flex bg-slate-100 rounded-full p-1">
             {Object.entries(LANG_OPTIONS).map(([key, label]) => (
                <button
                  key={key}
                  onClick={() => setLang(key as LangType)}
                  className={`
                    px-3 py-1 rounded-full text-xs font-bold transition-all
                    ${lang === key 
                      ? 'bg-white text-neo-primary shadow-sm' 
                      : 'text-slate-400 hover:text-slate-600'
                    }
                  `}
                >
                  {key}
                </button>
             ))}
           </div>
        </div>

        <button
          onClick={onSubmit}
          disabled={isLoading || !value.trim()}
          className={`
            w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 rounded-full font-bold text-white transition-all shadow-lg hover:shadow-glow
            ${isLoading || !value.trim() 
              ? 'bg-slate-300 cursor-not-allowed shadow-none' 
              : 'bg-gradient-to-r from-neo-primary to-neo-secondary hover:scale-105 active:scale-95'
            }
          `}
        >
          {isLoading ? (
            <Loader2 className="animate-spin" size={20} />
          ) : (
            <Send size={20} />
          )}
          <span>{isLoading ? 'Thinking...' : 'Generate Prompt'}</span>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check, RefreshCw, Sparkles, Zap } from 'lucide-react';

interface OutputSectionProps {
  content: string;
  categoryLabel: string;
  onReset?: () => void;
}

export const OutputSection: React.FC<OutputSectionProps> = ({ content, categoryLabel, onReset }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  return (
    <div className="flex flex-col h-full animate-in fade-in zoom-in-95 duration-500">

      {/* Header */}
      <div className="flex items-center justify-between mb-6">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-green-400 to-emerald-500 rounded-xl shadow-lg shadow-green-500/20 text-white">
               <Zap size={20} fill="currentColor" />
            </div>
            <div>
              <h2 className="text-lg font-bold text-slate-800">Optimized Result</h2>
              <div className="flex items-center gap-1.5">
                <span className="w-1.5 h-1.5 rounded-full bg-neo-primary"></span>
                <p className="text-xs font-medium text-slate-500 uppercase tracking-wide">
                  {categoryLabel}
                </p>
              </div>
            </div>
         </div>

         <div className="flex gap-2">
            {onReset && (
               <button 
                onClick={onReset}
                className="p-2.5 rounded-xl text-slate-400 hover:bg-slate-100 hover:text-slate-600 transition-colors"
                title="Reset"
               >
                 <RefreshCw size={18} />
               </button>
            )}
            <button
              onClick={handleCopy}
              className={`
                flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-sm transition-all
                ${copied 
                  ? 'bg-green-100 text-green-700' 
                  : 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg shadow-slate-900/20'
                }
              `}
            >
              {copied ? <Check size={16} /> : <Copy size={16} />}
              {copied ? 'Copied' : 'Copy'}
            </button>
         </div>
      </div>

      {/* Content */}
      <div className="relative flex-grow rounded-2xl bg-slate-50/50 border border-slate-200/50 overflow-hidden group">
        <div className="absolute inset-0 overflow-auto p-6 custom-scrollbar">
          <pre className="whitespace-pre-wrap font-mono text-sm text-slate-700 leading-relaxed">
            {content}
          </pre>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
