const App: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<PromptCategory>(PromptCategory.SOFTWARE);
  const [inputText, setInputText] = useState('');

  const [tone, setTone] = useState<ToneType>('PROFESSIONAL');
  const [lang, setLang] = useState<LangType>('ZH');

  const [result, setResult] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [streak, setStreak] = useState(1);

  const handleGenerate = async () => {
    if (!inputText.trim()) return;

    setIsLoading(true);
    setError(null);
    setResult(null);

    try {
      const optimizedText = await generateOptimizedPrompt(selectedCategory, inputText, { tone, lang });
      setResult(optimizedText);
      setStreak(s => s + 1);
    } catch (err: any) {
      setError(err.message || "Something went wrong. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = () => {
    setResult(null);
    setInputText('');
    setError(null);
  };

  return (
    <div className="min-h-screen py-8 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto flex flex-col gap-8">

