             <div className="w-20 h-20 bg-white rounded-2xl shadow-lg flex items-center justify-center mb-4 text-neo-primary rotate-3 transform hover:rotate-6 transition-transform">
                <Cloud size={40} className="fill-blue-100" />
             </div>
             <h2 className="font-bold text-slate-800 text-lg">Hi, I'm Mochi!</h2>
             <p className="text-slate-500 text-sm mt-1 mb-4">Ready to create some magic today?</p>
             <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
