import React from 'react';
import { Send, Loader2, Sparkles, Smile } from 'lucide-react';
import { ToneType, LangType } from '../types';
import { TONE_OPTIONS, LANG_OPTIONS } from '../constants';

interface InputSectionProps {
  value: string;
  onChange: (val: string) => void;
  onSubmit: () => void;
  isLoading: boolean;
  placeholder: string;
  tone: ToneType;
  setTone: (t: ToneType) => void;
  lang: LangType;
  setLang: (l: LangType) => void;
}

export const InputSection: React.FC<InputSectionProps> = ({ 
  value, 
  onChange, 
  onSubmit, 
  isLoading,
  placeholder,
  tone,
  setTone,
  lang,
  setLang
}) => {

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      onSubmit();
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full h-full">
      {/* Input Area container */}
      <div className="relative flex-grow group">
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          disabled={isLoading}
          className="w-full h-full min-h-[250px] p-6 rounded-[2rem] border-4 border-purple-100 bg-white text-lg font-bold text-pop-text placeholder-purple-200 resize-none focus:outline-none focus:border-pop-purple transition-colors shadow-inner-light"
        />
        <div className="absolute top-4 right-4 pointer-events-none">
          <Smile size={24} className="text-purple-200 group-focus-within:text-pop-purple transition-colors" />
        </div>
      </div>

      {/* Controls & Actions */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-4">

        <div className="flex items-center gap-3 w-full md:w-auto overflow-x-auto pb-2 md:pb-0 hide-scrollbar">
           {/* Tone Selector */}
           <div className="relative">
             <select 
               value={tone}
               onChange={(e) => setTone(e.target.value as ToneType)}
               className="appearance-none pl-4 pr-10 py-3 rounded-2xl bg-white border-2 border-purple-100 font-bold text-pop-text text-sm cursor-pointer hover:border-pop-purple focus:border-pop-purple focus:outline-none transition-colors shadow-pop active:shadow-pop-active active:translate-y-1"
             >
               {Object.entries(TONE_OPTIONS).map(([key, label]) => (
                 <option key={key} value={key}>{label}</option>
               ))}
             </select>
             <Sparkles size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-pop-purple pointer-events-none" />
           </div>

           {/* Lang Selector */}
           <div className="flex gap-1 bg-white p-1.5 rounded-2xl border-2 border-purple-100 shadow-sm">
             {Object.entries(LANG_OPTIONS).map(([key, label]) => (
                <button
                  key={key}
                  onClick={() => setLang(key as LangType)}
                  className={`
                    px-4 py-1.5 rounded-xl text-sm font-extrabold transition-all
                    ${lang === key 
                      ? 'bg-pop-mint text-pop-text shadow-sm' 
                      : 'text-gray-400 hover:text-pop-purple hover:bg-purple-50'
                    }
                  `}
                >
                  {key}
                </button>
             ))}
           </div>
        </div>

        <button
          onClick={onSubmit}
          disabled={isLoading || !value.trim()}
          className={`
            w-full md:w-auto flex items-center justify-center gap-2 px-8 py-4 rounded-2xl font-black text-white text-lg transition-all border-b-4
            ${isLoading || !value.trim() 
              ? 'bg-gray-300 border-gray-400 cursor-not-allowed opacity-50' 
              : 'bg-pop-purple border-purple-700 hover:bg-purple-500 hover:-translate-y-1 hover:shadow-lg active:translate-y-0 active:border-b-0 active:mt-1'
            }
          `}
        >
          {isLoading ? (
            <Loader2 className="animate-spin" size={24} strokeWidth={3} />
          ) : (
            <Send size={24} strokeWidth={3} />
          )}
          <span>{isLoading ? 'Thinking...' : 'GO!'}</span>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check, RefreshCw, Star, Heart } from 'lucide-react';

interface OutputSectionProps {
  content: string;
  categoryLabel: string;
  onReset?: () => void;
}

export const OutputSection: React.FC<OutputSectionProps> = ({ content, categoryLabel, onReset }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  return (
    <div className="flex flex-col h-full animate-in zoom-in-95 duration-500">

      {/* Header */}
      <div className="flex items-center justify-between mb-4">
         <div className="flex items-center gap-2">
            <div className="bg-pop-yellow text-pop-text px-3 py-1 rounded-full border-2 border-pop-text font-black text-sm shadow-pop flex items-center gap-2">
               <Star size={14} fill="currentColor" />
               <span>Ready!</span>
            </div>
            <span className="text-sm font-bold text-pop-text/50">For {categoryLabel}</span>
         </div>

         <div className="flex gap-2">
            {onReset && (
               <button 
                onClick={onReset}
                className="p-3 rounded-xl bg-white border-2 border-gray-200 text-gray-400 hover:text-pop-pink hover:border-pop-pink transition-all"
                title="Start Over"
               >
                 <RefreshCw size={20} strokeWidth={3} />
               </button>
            )}
            <button
              onClick={handleCopy}
              className={`
                flex items-center gap-2 px-5 py-2.5 rounded-xl font-black text-sm transition-all border-2
                ${copied 
                  ? 'bg-pop-mint border-pop-text text-pop-text' 
                  : 'bg-pop-text text-white border-pop-text hover:bg-purple-800 shadow-pop hover:-translate-y-1'
                }
              `}
            >
              {copied ? <Check size={18} strokeWidth={4} /> : <Copy size={18} strokeWidth={3} />}
              {copied ? 'COPIED!' : 'COPY'}
            </button>
         </div>
      </div>

      {/* Content */}
      <div className="relative flex-grow group">
        {/* Decorative background elements */}
        <div className="absolute -top-2 -right-2 w-16 h-16 bg-pop-pink rounded-full opacity-20 blur-xl"></div>
        <div className="absolute -bottom-2 -left-2 w-20 h-20 bg-pop-blue rounded-full opacity-20 blur-xl"></div>

        <div className="relative h-full w-full rounded-[2rem] bg-white border-4 border-pop-text/5 shadow-pop overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-8 bg-purple-50 border-b-2 border-purple-100 flex items-center gap-2 px-4">
             <div className="w-3 h-3 rounded-full bg-pop-pink"></div>
             <div className="w-3 h-3 rounded-full bg-pop-yellow"></div>
             <div className="w-3 h-3 rounded-full bg-pop-mint"></div>
          </div>
          <div className="absolute inset-0 top-8 overflow-auto p-6 custom-scrollbar">
            <pre className="whitespace-pre-wrap font-mono text-sm text-pop-text font-medium leading-relaxed">
              {content}
            </pre>
          </div>
        </div>
      </div>
    </div>
  );
};

